    "Instant alerts via WebSocket connections for real-time notifications",
    "Live dashboard updates without page refresh",
    "Real-time incident management and tracking",
    "Custom alert thresholds and notification rules",
    "Integration with SIEM and SOAR platforms"
  ],
  features: [
    { title: "WebSocket Streaming", description: "Real-time data streaming for instant updates" },
    { title: "Live Dashboards", description: "Dynamic visualizations that update in real-time" },
    { title: "Alert Management", description: "Customizable alerts with multiple notification channels" },
    { title: "Event Correlation", description: "Intelligent correlation of security events" },
    { title: "Historical Analysis", description: "Real-time view with historical data access" }
  ],
  howItWorks: [
    { title: "Agent Deployment", description: "Lightweight agents collect security events" },
    { title: "Event Streaming", description: "Events are streamed in real-time via WebSocket" },
    { title: "Processing", description: "Events are analyzed and correlated instantly" },
    { title: "Alert Delivery", description: "Alerts are delivered instantly via configured channels" }
